    for row in sorted((item for item in rows if isinstance(item, dict)), key=lambda item: str(item.get("queue_id", ""))):
        queue_id = str(row.get("queue_id", "")).strip()
        if not queue_id:
            continue
        owner_kind = str(row.get("owner_kind", "")).strip()
