def _ensure_reenactment_requests(state: dict) -> List[dict]:
    rows = state.get("reenactment_requests")
    if not isinstance(rows, list):
        rows = []
    normalized: List[dict] = []
    for row in sorted((item for item in rows if isinstance(item, dict)), key=lambda item: str(item.get("request_id", ""))):
        request_id = str(row.get("request_id", "")).strip()
        target_id = str(row.get("target_id", "")).strip()
        if not request_id or not target_id:
            continue
        tick_range = dict(row.get("tick_range") or {})
        start_tick = max(0, _as_int(tick_range.get("start_tick", 0), 0))
        end_tick = max(start_tick, _as_int(tick_range.get("end_tick", start_tick), start_tick))
        fidelity = str(row.get("desired_fidelity", "macro")).strip() or "macro"
        if fidelity not in ("macro", "meso", "micro"):
            fidelity = "macro"
        normalized.append(
            {
                "schema_version": "1.0.0",
                "request_id": request_id,
                "target_id": target_id,
                "tick_range": {
                    "start_tick": int(start_tick),
                    "end_tick": int(end_tick),
                },
                "desired_fidelity": fidelity,
                "max_cost_units": max(0, _as_int(row.get("max_cost_units", 0), 0)),
                "requester_subject_id": str(row.get("requester_subject_id", "")).strip() or "subject.system",
                "extensions": dict(row.get("extensions") or {}) if isinstance(row.get("extensions"), dict) else {},
            }
        )
    state["reenactment_requests"] = normalized
    return [dict(row) for row in normalized]


def _ensure_reenactment_artifacts(state: dict) -> List[dict]:
    rows = state.get("reenactment_artifacts")
    if not isinstance(rows, list):
        rows = []
    normalized: List[dict] = []
    for row in sorted((item for item in rows if isinstance(item, dict)), key=lambda item: str(item.get("reenactment_id", ""))):
        reenactment_id = str(row.get("reenactment_id", "")).strip()
        request_id = str(row.get("request_id", "")).strip()
        if not reenactment_id or not request_id:
            continue
        fidelity = str(row.get("fidelity_achieved", "macro")).strip() or "macro"
        if fidelity not in ("macro", "meso", "micro"):
            fidelity = "macro"
        output_timeline_ref = str(row.get("output_timeline_ref", "")).strip()
        if not output_timeline_ref:
            output_timeline_ref = "timeline.{}".format(reenactment_id)
        payload = {
            "schema_version": "1.0.0",
            "reenactment_id": reenactment_id,
            "request_id": request_id,
            "inputs_hash": str(row.get("inputs_hash", "")).strip(),
            "output_timeline_ref": output_timeline_ref,
            "fidelity_achieved": fidelity,
            "deterministic_fingerprint": str(row.get("deterministic_fingerprint", "")).strip(),
            "extensions": dict(row.get("extensions") or {}) if isinstance(row.get("extensions"), dict) else {},
        }
        if not payload["deterministic_fingerprint"]:
            fingerprint_payload = dict(payload)
            fingerprint_payload["deterministic_fingerprint"] = ""
            payload["deterministic_fingerprint"] = canonical_sha256(fingerprint_payload)
        normalized.append(payload)
    state["reenactment_artifacts"] = normalized
    return [dict(row) for row in normalized]


def _ensure_fidelity_decision_entries(state: dict) -> List[dict]:
    rows = state.get("fidelity_decision_entries")
    if not isinstance(rows, list):
        rows = []
    normalized: Dict[str, dict] = {}
    for row in sorted((item for item in rows if isinstance(item, dict)), key=lambda item: str(item.get("allocation_id", ""))):
        allocation_id = str(row.get("allocation_id", "")).strip()
        request_id = str(row.get("fidelity_request_id", "")).strip()
        if not allocation_id or not request_id:
            continue
        payload = {
            "schema_version": "1.0.0",
            "fidelity_request_id": request_id,
            "allocation_id": allocation_id,
            "resolved_level": str(row.get("resolved_level", "macro")).strip() or "macro",
            "cost_allocated": max(0, _as_int(row.get("cost_allocated", 0), 0)),
            "downgrade_reason": str(row.get("downgrade_reason", "")).strip() or "none",
            "envelope_id": str(row.get("envelope_id", "")).strip() or "budget.unknown",
            "policy_id": str(row.get("policy_id", "")).strip() or DEFAULT_FIDELITY_POLICY_ID,
            "refusal_codes": _sorted_tokens(list(row.get("refusal_codes") or [])),
            "deterministic_fingerprint": str(row.get("deterministic_fingerprint", "")).strip(),
            "extensions": dict(row.get("extensions") or {}) if isinstance(row.get("extensions"), dict) else {},
        }
        if not payload["deterministic_fingerprint"]:
            seed = dict(payload)
            seed["deterministic_fingerprint"] = ""
            payload["deterministic_fingerprint"] = canonical_sha256(seed)
        normalized[allocation_id] = payload
    ordered = [dict(normalized[key]) for key in sorted(normalized.keys())]
    state["fidelity_decision_entries"] = ordered
    return ordered


def _append_fidelity_decision_entries(
    state: dict,
    *,
    entries: List[dict],
    process_id: str,
    tick: int,
) -> List[dict]:
    existing = _ensure_fidelity_decision_entries(state)
    merged: Dict[str, dict] = dict(
        (str(row.get("allocation_id", "")).strip(), dict(row))
        for row in existing
        if str(row.get("allocation_id", "")).strip()
    )
    for row in list(entries or []):
        if not isinstance(row, dict):
            continue
        allocation_id = str(row.get("allocation_id", "")).strip()
        request_id = str(row.get("fidelity_request_id", "")).strip()
        if not allocation_id or not request_id:
            continue
        payload = dict(row)
        ext = dict(payload.get("extensions") or {})
        ext["process_id"] = str(process_id).strip()
        ext["tick"] = int(max(0, _as_int(tick, 0)))
        payload["extensions"] = dict((str(key), ext[key]) for key in sorted(ext.keys()) if str(key).strip())
        merged[allocation_id] = payload
    state["fidelity_decision_entries"] = [dict(merged[key]) for key in sorted(merged.keys())]
    return _ensure_fidelity_decision_entries(state)


