def _agent_current_volume_id(agent_row: dict) -> str:
    row = dict(agent_row or {})
    ext = dict(row.get("extensions") or {}) if isinstance(row.get("extensions"), dict) else {}
    for token in (
        row.get("interior_volume_id"),
        ext.get("interior_volume_id"),
        row.get("position_ref"),
        row.get("location_ref"),
    ):
        value = str(token or "").strip()
        if value:
            return value
    return ""


def _set_agent_current_volume_id(agent_row: dict, volume_id: str) -> None:
    token = str(volume_id).strip()
    if not token:
        return
    agent_row["interior_volume_id"] = token
    ext = dict(agent_row.get("extensions") or {}) if isinstance(agent_row.get("extensions"), dict) else {}
    ext["interior_volume_id"] = token
    agent_row["extensions"] = ext


def _pose_slot_graph_row(state: dict, pose_slot_row: dict) -> dict:
    slot = dict(pose_slot_row or {})
    slot_ext = dict(slot.get("extensions") or {}) if isinstance(slot.get("extensions"), dict) else {}
    desired_graph_id = str(slot_ext.get("interior_graph_id", "")).strip()
    if desired_graph_id:
        for graph in sorted(
            (item for item in list(state.get("interior_graphs") or []) if isinstance(item, dict)),
            key=lambda item: str(item.get("graph_id", "")),
        ):
            if str(graph.get("graph_id", "")).strip() == desired_graph_id:
                return dict(graph)
    parent_assembly_id = str(slot.get("parent_assembly_id", "")).strip()
    if parent_assembly_id:
        for binding in sorted(
            (item for item in list(state.get("interior_structure_bindings") or []) if isinstance(item, dict)),
            key=lambda item: (str(item.get("structure_id", "")), str(item.get("graph_id", ""))),
        ):
            if str(binding.get("structure_id", "")).strip() != parent_assembly_id:
                continue
            graph_id = str(binding.get("graph_id", "")).strip()
            if not graph_id:
                continue
            for graph in sorted(
                (item for item in list(state.get("interior_graphs") or []) if isinstance(item, dict)),
                key=lambda item: str(item.get("graph_id", "")),
            ):
                if str(graph.get("graph_id", "")).strip() == graph_id:
                    return dict(graph)
    slot_volume_id = str(slot.get("interior_volume_id", "")).strip()
    if slot_volume_id:
        for graph in sorted(
            (item for item in list(state.get("interior_graphs") or []) if isinstance(item, dict)),
            key=lambda item: str(item.get("graph_id", "")),
        ):
            graph_volume_ids = set(_sorted_tokens(list(graph.get("volumes") or [])))
            if slot_volume_id in graph_volume_ids:
                return dict(graph)
    return {}


def _pose_slot_accessible_by_path(
    *,
    state: dict,
    agent_row: dict,
    pose_slot_row: dict,
) -> bool:
    slot = dict(pose_slot_row or {})
    if not bool(slot.get("requires_access_path", True)):
        return True
    from_volume_id = _agent_current_volume_id(agent_row)
    to_volume_id = str(slot.get("interior_volume_id", "")).strip()
    if (not from_volume_id) or (not to_volume_id):
        return False
    if from_volume_id == to_volume_id:
        return True
    graph_row = _pose_slot_graph_row(state, slot)
    if not graph_row:
        return False
    try:
        return bool(
            path_exists(
                graph_row=graph_row,
                volume_rows=list(state.get("interior_volumes") or []),
                portal_rows=list(state.get("interior_portals") or []),
                from_volume_id=from_volume_id,
                to_volume_id=to_volume_id,
                portal_state_rows=list(state.get("interior_portal_state_machines") or []),
            )
        )
    except InteriorError:
        return False


def _vehicle_row_for_pose_slot(state: dict, pose_slot_row: Mapping[str, object]) -> dict:
    slot = dict(pose_slot_row or {})
    slot_id = str(slot.get("pose_slot_id", "")).strip()
    slot_ext = dict(slot.get("extensions") or {}) if isinstance(slot.get("extensions"), Mapping) else {}
    explicit_vehicle_id = str(slot_ext.get("vehicle_id", "")).strip()
    vehicle_rows = _vehicle_rows_by_id(state)
    if explicit_vehicle_id:
        return dict(vehicle_rows.get(explicit_vehicle_id) or {})
    parent_assembly_id = str(slot.get("parent_assembly_id", "")).strip()
    if parent_assembly_id and parent_assembly_id in vehicle_rows:
        return dict(vehicle_rows.get(parent_assembly_id) or {})
    for vehicle_id in sorted(vehicle_rows.keys()):
        vehicle_row = dict(vehicle_rows.get(vehicle_id) or {})
        pose_slot_ids = set(_sorted_tokens(list(vehicle_row.get("pose_slot_ids") or [])))
        if slot_id and slot_id in pose_slot_ids:
            return vehicle_row
    return {}


def _inventory_debit(
    *,
    inventory_index: Dict[str, dict],
    node_id: str,
    material_id: str,
    mass: int,
    batch_id: str,
) -> None:
    node_token = str(node_id).strip()
    material_token = str(material_id).strip()
    batch_token = str(batch_id).strip()
    mass_raw = max(0, _as_int(mass, 0))
    node_row = dict(inventory_index.get(node_token) or {})
    if not node_row:
        raise LogisticsError(
            "refusal.logistics.insufficient_stock",
            "node inventory '{}' is missing".format(node_token),
            {"node_id": node_token},
        )
    stocks = dict(node_row.get("material_stocks") or {})
    available = max(0, _as_int(stocks.get(material_token, 0), 0))
    if available < mass_raw:
        raise LogisticsError(
            "refusal.logistics.insufficient_stock",
            "insufficient stock at node '{}'".format(node_token),
            {
                "node_id": node_token,
                "material_id": material_token,
                "required_mass": str(mass_raw),
                "available_mass": str(available),
            },
        )
    stocks[material_token] = int(available - mass_raw)
    batch_refs = _sorted_tokens(list(node_row.get("batch_refs") or []))
    if batch_token and batch_token not in batch_refs:
        batch_refs.append(batch_token)
    node_row["material_stocks"] = dict((k, v) for k, v in sorted(stocks.items(), key=lambda item: str(item[0])) if _as_int(v, 0) > 0)
    node_row["batch_refs"] = _sorted_tokens(batch_refs)
    inventory_index[node_token] = normalize_node_inventory(node_row)


def _inventory_credit(
    *,
    inventory_index: Dict[str, dict],
    node_id: str,
    material_id: str,
    mass: int,
    batch_id: str,
) -> None:
    node_token = str(node_id).strip()
    material_token = str(material_id).strip()
    batch_token = str(batch_id).strip()
    mass_raw = max(0, _as_int(mass, 0))
    node_row = dict(inventory_index.get(node_token) or {"schema_version": "1.0.0", "node_id": node_token, "material_stocks": {}, "batch_refs": [], "inventory_hash": "", "extensions": {}})
    stocks = dict(node_row.get("material_stocks") or {})
    stocks[material_token] = max(0, _as_int(stocks.get(material_token, 0), 0)) + int(mass_raw)
    batch_refs = _sorted_tokens(list(node_row.get("batch_refs") or []))
    if batch_token:
        batch_refs = _sorted_tokens(batch_refs + [batch_token])
    node_row["material_stocks"] = dict((k, v) for k, v in sorted(stocks.items(), key=lambda item: str(item[0])) if _as_int(v, 0) > 0)
    node_row["batch_refs"] = batch_refs
    inventory_index[node_token] = normalize_node_inventory(node_row)


